                     style="width: @GetProgressPercent(shipment.Status)%"
                     aria-valuenow="@GetProgressPercent(shipment.Status)"
                     aria-valuemin="0" aria-valuemax="100">
                    @shipment.Status
                </div>
            </div>
        </div>
    </div>
}

<hr class="my-4" />

<h3>My Shipments</h3>
<p class="text-muted">View all shipments associated with your account.</p>
<button class="btn btn-outline-primary mb-3" @onclick="LoadMyShipments">Load My Shipments</button>

@if (myShipments is not null)
{
    @if (myShipments.Count == 0)
    {
        <p>No shipments found for your account.</p>
    }
    else
    {
        <div class="list-group">
            @foreach (var s in myShipments)
            {
                <div class="list-group-item">
                    <div class="d-flex w-100 justify-content-between">
                        <h6 class="mb-1"><code>@s.TrackingNumber</code> — @s.Destination</h6>
                        <span class="badge @GetStatusBadgeClass(s.Status)">@s.Status</span>
                    </div>
                    <small class="text-muted">
                        Est. delivery: @(s.EstimatedDelivery?.ToString("MMM dd, yyyy") ?? "TBD")
                    </small>
                </div>
            }
        </div>
    }
}

