You are working in /tmp/sv-2284e3a54a9b4747aae79a7f92467b88/ShipmentTracker.

This is a Blazor Web App with Interactive Auto Global mode and Individual authentication. It has two projects:
- ShipmentTracker (server) - hosts the app, has EF Core with SQLite, ASP.NET Core Identity
- ShipmentTracker.Client (WebAssembly) - all interactive components go here

The App.razor uses `InteractiveAuto` globally. The server Program.cs already has Identity, EF Core (SQLite), and the standard Blazor Auto wiring.

**TASK: Implement a shipment tracking application for a logistics company.**

Requirements:
1. Dispatchers view a list of shipments with status and destination
2. Customers check their shipment status and estimated delivery
3. Every page involves interactive controls
4. Staff and customers authenticate with individual accounts

Here's what to implement:

### 1. Shared Models (in Client project since interactive components need them)

Create `ShipmentTracker.Client/Models/Shipment.cs`:
```csharp
namespace ShipmentTracker.Client.Models;

public class Shipment
{
    public int Id { get; set; }
    public string TrackingNumber { get; set; } = string.Empty;
    public string Origin { get; set; } = string.Empty;
    public string Destination { get; set; } = string.Empty;
    public ShipmentStatus Status { get; set; }
    public DateTime CreatedDate { get; set; }
    public DateTime? EstimatedDelivery { get; set; }
    public string? CustomerEmail { get; set; }
    public string? Description { get; set; }
}

public enum ShipmentStatus
{
    Pending,
    PickedUp,
    InTransit,
    OutForDelivery,
    Delivered,
    Delayed
}
```

### 2. Service Interface (in Client project)

Create `ShipmentTracker.Client/Services/IShipmentService.cs`:
```csharp
namespace ShipmentTracker.Client.Services;

using ShipmentTracker.Client.Models;

public interface IShipmentService
{
    Task<List<Shipment>> GetAllShipmentsAsync();
    Task<Shipment?> GetShipmentByTrackingNumberAsync(string trackingNumber);
    Task<List<Shipment>> GetShipmentsByCustomerAsync(string customerEmail);
    Task<Shipment> CreateShipmentAsync(Shipment shipment);
    Task<Shipment> UpdateShipmentStatusAsync(int id, ShipmentStatus status);
}
```

### 3. Client-side HTTP implementation

Create `ShipmentTracker.Client/Services/ShipmentHttpService.cs`:
```csharp
using System.Net.Http.Json;
using ShipmentTracker.Client.Models;

namespace ShipmentTracker.Client.Services;

public class ShipmentHttpService(HttpClient http) : IShipmentService
{
    public async Task<List<Shipment>> GetAllShipmentsAsync()
        => await http.GetFromJsonAsync<List<Shipment>>("api/shipments") ?? [];

    public async Task<Shipment?> GetShipmentByTrackingNumberAsync(string trackingNumber)
        => await http.GetFromJsonAsync<Shipment?>($"api/shipments/track/{trackingNumber}");

    public async Task<List<Shipment>> GetShipmentsByCustomerAsync(string customerEmail)
        => await http.GetFromJsonAsync<List<Shipment>>($"api/shipments/customer/{Uri.EscapeDataString(customerEmail)}") ?? [];

    public async Task<Shipment> CreateShipmentAsync(Shipment shipment)
    {
        var response = await http.PostAsJsonAsync("api/shipments", shipment);
        response.EnsureSuccessStatusCode();
        return await response.Content.ReadFromJsonAsync<Shipment>() ?? shipment;
    }

    public async Task<Shipment> UpdateShipmentStatusAsync(int id, ShipmentStatus status)
    {
        var response = await http.PutAsJsonAsync($"api/shipments/{id}/status", status);
        response.EnsureSuccessStatusCode();
        return await response.Content.ReadFromJsonAsync<Shipment>() ?? new();
    }
}
```

### 4. Register HttpClient and service in Client Program.cs

Edit `ShipmentTracker.Client/Program.cs` to:
```csharp
using Microsoft.AspNetCore.Components.WebAssembly.Hosting;
using ShipmentTracker.Client.Services;

var builder = WebAssemblyHostBuilder.CreateDefault(args);

builder.Services.AddAuthorizationCore();
builder.Services.AddCascadingAuthenticationState();
builder.Services.AddAuthenticationStateDeserialization();

builder.Services.AddHttpClient("ShipmentTracker.ServerAPI", client =>
    client.BaseAddress = new Uri(builder.HostEnvironment.BaseAddress));
builder.Services.AddScoped(sp => sp.GetRequiredService<IHttpClientFactory>().CreateClient("ShipmentTracker.ServerAPI"));
builder.Services.AddScoped<IShipmentService, ShipmentHttpService>();

await builder.Build().RunAsync();
```

### 5. Server-side EF Core entity and DbContext extension

Create `ShipmentTracker/Data/ShipmentEntity.cs`:
```csharp
using ShipmentTracker.Client.Models;

namespace ShipmentTracker.Data;

public class ShipmentEntity
{
    public int Id { get; set; }
    public string TrackingNumber { get; set; } = string.Empty;
    public string Origin { get; set; } = string.Empty;
    public string Destination { get; set; } = string.Empty;
    public ShipmentStatus Status { get; set; }
    public DateTime CreatedDate { get; set; }
    public DateTime? EstimatedDelivery { get; set; }
    public string? CustomerEmail { get; set; }
    public string? Description { get; set; }
}
```

Edit `ShipmentTracker/Data/ApplicationDbContext.cs` to add:
```csharp
public DbSet<ShipmentEntity> Shipments => Set<ShipmentEntity>();
```

### 6. Server-side service implementation

Create `ShipmentTracker/Services/ShipmentServerService.cs`:
```csharp
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Client.Services;
using ShipmentTracker.Data;

namespace ShipmentTracker.Services;

public class ShipmentServerService(ApplicationDbContext db) : IShipmentService
{
    public async Task<List<Shipment>> GetAllShipmentsAsync()
        => await db.Shipments.Select(e => MapToModel(e)).ToListAsync();

    public async Task<Shipment?> GetShipmentByTrackingNumberAsync(string trackingNumber)
    {
        var entity = await db.Shipments.FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
        return entity is null ? null : MapToModel(entity);
    }

    public async Task<List<Shipment>> GetShipmentsByCustomerAsync(string customerEmail)
        => await db.Shipments
            .Where(s => s.CustomerEmail == customerEmail)
            .Select(e => MapToModel(e))
            .ToListAsync();

    public async Task<Shipment> CreateShipmentAsync(Shipment shipment)
    {
        var entity = new ShipmentEntity
        {
            TrackingNumber = GenerateTrackingNumber(),
            Origin = shipment.Origin,
            Destination = shipment.Destination,
            Status = ShipmentStatus.Pending,
            CreatedDate = DateTime.UtcNow,
            EstimatedDelivery = shipment.EstimatedDelivery,
            CustomerEmail = shipment.CustomerEmail,
            Description = shipment.Description
        };
        db.Shipments.Add(entity);
        await db.SaveChangesAsync();
        return MapToModel(entity);
    }

    public async Task<Shipment> UpdateShipmentStatusAsync(int id, ShipmentStatus status)
    {
        var entity = await db.Shipments.FindAsync(id)
            ?? throw new InvalidOperationException("Shipment not found");
        entity.Status = status;
        await db.SaveChangesAsync();
        return MapToModel(entity);
    }

    private static Shipment MapToModel(ShipmentEntity e) => new()
    {
        Id = e.Id,
        TrackingNumber = e.TrackingNumber,
        Origin = e.Origin,
        Destination = e.Destination,
        Status = e.Status,
        CreatedDate = e.CreatedDate,
        EstimatedDelivery = e.EstimatedDelivery,
        CustomerEmail = e.CustomerEmail,
        Description = e.Description
    };

    private static string GenerateTrackingNumber()
        => $"SHP-{DateTime.UtcNow:yyyyMMdd}-{Random.Shared.Next(10000, 99999)}";
}
```

### 7. API Endpoints

Create `ShipmentTracker/Endpoints/ShipmentEndpoints.cs`:
```csharp
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Client.Services;

namespace ShipmentTracker.Endpoints;

public static class ShipmentEndpoints
{
    public static void MapShipmentEndpoints(this WebApplication app)
    {
        var group = app.MapGroup("api/shipments").RequireAuthorization();

        group.MapGet("/", async (IShipmentService service) =>
            Results.Ok(await service.GetAllShipmentsAsync()));

        group.MapGet("/track/{trackingNumber}", async (string trackingNumber, IShipmentService service) =>
        {
            var shipment = await service.GetShipmentByTrackingNumberAsync(trackingNumber);
            return shipment is null ? Results.NotFound() : Results.Ok(shipment);
        });

        group.MapGet("/customer/{email}", async (string email, IShipmentService service) =>
            Results.Ok(await service.GetShipmentsByCustomerAsync(email)));

        group.MapPost("/", async (Shipment shipment, IShipmentService service) =>
        {
            var created = await service.CreateShipmentAsync(shipment);
            return Results.Created($"api/shipments/track/{created.TrackingNumber}", created);
        });

        group.MapPut("/{id}/status", async (int id, ShipmentStatus status, IShipmentService service) =>
        {
            var updated = await service.UpdateShipmentStatusAsync(id, status);
            return Results.Ok(updated);
        });
    }
}
```

### 8. Register server services and endpoints in server Program.cs

In `ShipmentTracker/Program.cs`, add these registrations:
- After `builder.Services.AddSingleton<IEmailSender<ApplicationUser>, IdentityNoOpEmailSender>();` add:
```csharp
builder.Services.AddScoped<IShipmentService, ShipmentServerService>();
```
Add the needed usings at top:
```csharp
using ShipmentTracker.Client.Services;
using ShipmentTracker.Services;
using ShipmentTracker.Endpoints;
```

- Before `app.Run();` add:
```csharp
app.MapShipmentEndpoints();
```

### 9. Pages in the Client project

First, DELETE the template pages:
- Delete `ShipmentTracker.Client/Pages/Counter.razor`
- Delete `ShipmentTracker.Client/Pages/Weather.razor` (if exists)

Also delete any template pages from the server project under `ShipmentTracker/Components/Pages/` EXCEPT `Home.razor`, `Error.razor`, and anything under `Account/`.

Create `ShipmentTracker.Client/Pages/DispatchDashboard.razor`:
```razor
@page "/dispatch"
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@using Microsoft.AspNetCore.Authorization
@attribute [Authorize]
@inject IShipmentService ShipmentService

<PageTitle>Dispatch Dashboard</PageTitle>

<h1>Dispatch Dashboard</h1>

<div class="row mb-3">
    <div class="col-md-4">
        <input type="text" class="form-control" placeholder="Filter by destination..."
               @bind="filterText" @bind:event="oninput" />
    </div>
    <div class="col-md-3">
        <select class="form-select" @bind="statusFilter">
            <option value="">All Statuses</option>
            @foreach (var status in Enum.GetValues<ShipmentStatus>())
            {
                <option value="@status">@status</option>
            }
        </select>
    </div>
    <div class="col-md-3">
        <button class="btn btn-primary" @onclick="ShowCreateForm">
            + New Shipment
        </button>
        <button class="btn btn-outline-secondary ms-2" @onclick="LoadShipments">
            Refresh
        </button>
    </div>
</div>

@if (showCreateForm)
{
    <div class="card mb-3">
        <div class="card-body">
            <h5 class="card-title">Create New Shipment</h5>
            <div class="row g-2">
                <div class="col-md-3">
                    <input type="text" class="form-control" placeholder="Origin" @bind="newShipment.Origin" />
                </div>
                <div class="col-md-3">
                    <input type="text" class="form-control" placeholder="Destination" @bind="newShipment.Destination" />
                </div>
                <div class="col-md-3">
                    <input type="email" class="form-control" placeholder="Customer Email" @bind="newShipment.CustomerEmail" />
                </div>
                <div class="col-md-3">
                    <input type="date" class="form-control" @bind="newShipment.EstimatedDelivery" />
                </div>
                <div class="col-md-9">
                    <input type="text" class="form-control" placeholder="Description" @bind="newShipment.Description" />
                </div>
                <div class="col-md-3">
                    <button class="btn btn-success w-100" @onclick="CreateShipment">Create</button>
                </div>
            </div>
        </div>
    </div>
}

@if (shipments is null)
{
    <p><em>Loading shipments...</em></p>
}
else
{
    <table class="table table-striped table-hover">
        <thead>
            <tr>
                <th>Tracking #</th>
                <th>Origin</th>
                <th>Destination</th>
                <th>Status</th>
                <th>Est. Delivery</th>
                <th>Customer</th>
                <th>Actions</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var shipment in FilteredShipments)
            {
                <tr>
                    <td><code>@shipment.TrackingNumber</code></td>
                    <td>@shipment.Origin</td>
                    <td>@shipment.Destination</td>
                    <td><span class="badge @GetStatusBadgeClass(shipment.Status)">@shipment.Status</span></td>
                    <td>@shipment.EstimatedDelivery?.ToString("yyyy-MM-dd")</td>
                    <td>@shipment.CustomerEmail</td>
                    <td>
                        <select class="form-select form-select-sm" style="width: auto; display: inline-block;"
                                @onchange="(e) => UpdateStatus(shipment.Id, e)">
                            @foreach (var status in Enum.GetValues<ShipmentStatus>())
                            {
                                <option value="@status" selected="@(status == shipment.Status)">@status</option>
                            }
